mapper.select:
SELECT COUNT(1)
FROM tb_sku
WHERE sku_code = #{skuCode}

    AND id  <>  #{excludeId}

SELECT s.id AS skuId, s.product_id AS productId, p.name AS productName, p.sub_title AS productSubTitle, s.name AS skuName, COALESCE(s.image_url, p.main_image_url) AS imageUrl, s.tryon_image_url AS tryOnImageUrl, s.tryon_category AS tryOnCategory, s.price AS price, s.stock AS stock, s.tryon_sort AS tryOnSort FROM tb_sku s INNER JOIN tb_product p ON p.id = s.product_id WHERE p.status = 1 AND s.status = 1 AND s.ai_tryon_enabled = 1 AND s.tryon_category = #{slotType}
AND ( p.name LIKE CONCAT('%', #{keyword}, '%') OR p.sub_title LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY COALESCE(s.tryon_sort, 999999) ASC, s.id DESC LIMIT #{limit} OFFSET #{offset}
